SELECT program_name 
FROM programs 
WHERE credits > 100;

SELECT student_id, start_date 
FROM students 
WHERE start_date > '2023-01-01';

SELECT professor_id 
FROM professors 
WHERE title = 'PhD';

SELECT first_name, last_name 
FROM members 
WHERE date_of_birth < '2000-01-01';

SELECT m.first_name, m.last_name, s.start_date 
FROM members m 
JOIN students s ON m.member_id = s.student_id;

SELECT class_id, ROUND(AVG(grade), 2) as avg_grade 
FROM enrollments 
GROUP BY class_id;

SELECT student_id, SUM(absences) as total_absences 
FROM enrollments 
GROUP BY student_id;

SELECT status, COUNT(*) as total_students 
FROM enrollments 
GROUP BY status;

SELECT first_name, last_name, phone_number 
FROM members 
WHERE phone_number IS NULL OR phone_number = '';
